  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import java.util.List;
  import org.apache.log4j.Logger;
  import sailpoint.object.Attributes;
  import sailpoint.tools.Util;
  import java.util.Map;
  import java.util.HashMap;

 
  Logger logger = Logger.getLogger("com.CustomLogs");
  String newType = null;    
      String previousType= null; 
      String newEmplClass = null;    
      String previousEmplClass= null; 
  try{
    if(previousIdentity!= null && newIdentity!= null){

      boolean isInactiveUser=newIdentity.isInactive();
      
      if(previousIdentity.isInactive() && !newIdentity.isInactive()){
      	 return false;
      }
	  
      if(!isInactiveUser){

       newType = newIdentity.getStringAttribute("type");    
       previousType= previousIdentity.getStringAttribute("type"); 
       newEmplClass = newIdentity.getStringAttribute("employeeClass");    
       previousEmplClass= previousIdentity.getStringAttribute("employeeClass"); 

      List emplClassValues=new ArrayList();
      Custom gsuiteCustomObject = context.getObject(Custom.class,"Ascension-Custom-Gsuite");
      if(gsuiteCustomObject != null){
        Attributes attr = gsuiteCustomObject.getAttributes();
        if(attr != null){
          Map objectMap = attr.getMap();
          if(objectMap != null){
            emplClassValues = objectMap.get("emplClassForAutoProvisioning");
            
          }
        }
      }
      if(newType!=null && newType.equalsIgnoreCase("contractor")){
        
      //When contractor empl class value changes to c28
      if(newEmplClass!=null  && emplClassValues.contains(newEmplClass) && ( previousEmplClass==null || (previousEmplClass!=null && !emplClassValues.contains(previousEmplClass)))){

        return true;

      }
      //When contractor empl class value changes from c28 to other value
      if( previousEmplClass!=null  && emplClassValues.contains(previousEmplClass) &&(newEmplClass==null || (newEmplClass!=null && !emplClassValues.contains(newEmplClass) ))){
        
        return true;

      }
    }
    }
    }
    return false;

  }catch(Exception e){
    log.error("Exception= ");
    e.printStackTrace();
    throw e;
  }
